package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        // Use the DEFAULT instance directly
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        // Create a new CSVFormat instance with nullString set to null using withNullString(null)
        CSVFormat formatWithNullNullString = csvFormat.withNullString(null);
        assertFalse(formatWithNullNullString.isNullStringSet());
    }

    @Test
    public void testIsNullStringSet_whenNullStringIsNotNull() throws Exception {
        // Create a new CSVFormat instance with nullString set to "NULL" using withNullString("NULL")
        CSVFormat formatWithNullString = csvFormat.withNullString("NULL");
        assertTrue(formatWithNullString.isNullStringSet());
    }
}
